// // This LFSR generates pseudo-random values using a feedback polynomial of x^8 - x^6 - x^5 - x^4 + 1
module lfsr_8bit (  
    input clk,  
    input reset,  
    input [7:0] seed,  
    output reg [7:0] lfsr_out  
);  
    wire feedback;  
    assign feedback = lfsr_out[7] ^ lfsr_out[5] ^ lfsr_out[4] ^ lfsr_out[3];  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            lfsr_out <= seed;  
        end else begin  
            lfsr_out <= {lfsr_out[6:0], feedback};  
        end  
    end  
endmodule
